import{c as t,Q as a,j as n,m as s}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Agentic Harness Engineering: LLMs as the New OS","description":"","frontmatter":{"title":"Agentic Harness Engineering: LLMs as the New OS","date":"2026-04-01T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-01-agentic-harness-engineering-decodingai.md","filePath":"research/ai-articles/scored/2026-04-01-agentic-harness-engineering-decodingai.md","lastUpdated":1779796674000}'),i={name:"research/ai-articles/scored/2026-04-01-agentic-harness-engineering-decodingai.md"};function r(o,e,l,h,d,c){return a(),n("div",null,[...e[0]||(e[0]=[s('<blockquote><p>Source: <a href="https://www.decodingai.com/p/agentic-harness-engineering" target="_blank" rel="noreferrer">https://www.decodingai.com/p/agentic-harness-engineering</a> Fetched: 2026-05-08</p></blockquote><h1 id="agentic-harness-engineering-llms-as-the-new-os" tabindex="-1">Agentic Harness Engineering: LLMs as the New OS <a class="header-anchor" href="#agentic-harness-engineering-llms-as-the-new-os" aria-label="Permalink to &quot;Agentic Harness Engineering: LLMs as the New OS&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>At a financial personal assistant startup, the author discovered that stripping away complex frameworks like LlamaIndex and MCP in favor of plain Python, simple API calls, and a custom ReAct engine produced better results. This experience revealed a critical insight: the LLM model itself isn&#39;t the bottleneck—the infrastructure surrounding it determines whether an agent functions reliably in production.</p><p>Most engineering teams obsess over model selection, debating choices between GPT-4o, Claude Opus, and Gemini while chasing benchmark scores. However, the equation involves two equal parts: the model and the harness. TerminalBench 2.0 demonstrated this principle when changing only the harness architecture moved the DeepAgent from LangChain outside the top 30 to the top 5.</p><h2 id="what-is-a-harness" tabindex="-1">What Is a Harness? <a class="header-anchor" href="#what-is-a-harness" aria-label="Permalink to &quot;What Is a Harness?&quot;">​</a></h2><p>The concept of a harness draws from an agricultural analogy. A horse possesses inherent power but remains useless for farming without a harness to direct its strength toward productive work. Similarly, LLMs have intelligence but require tools, memory, state management, guardrails, and orchestration to operate reliably.</p><p>LangChain provides a clear definition: <strong>&quot;An agent equals a model plus a harness.&quot;</strong> The harness encompasses every piece of code, configuration, and execution logic excluding the model itself.</p><p>A basic agent consists of a model, prompt, tools, and planning loop. A comprehensive harness extends this foundation by incorporating:</p><ul><li>Memory systems</li><li>Guardrails and safety constraints</li><li>Advanced orchestration mechanisms</li><li>Context engineering techniques</li><li>Multi-agent coordination</li></ul><p>The harness typically includes a serving layer connecting the agent to various interfaces—terminal applications, web dashboards, IDE plugins, and messaging applications like Telegram.</p><p>Ultimately, harness engineering means constructing real software applications using LLMs as the operating system. Applications like Claude Code, OpenCode, OpenClaw, and Codex exemplify this approach. While the underlying model could theoretically be swapped, the genuine engineering value resides within the harness itself.</p><h2 id="three-levels-of-engineering" tabindex="-1">Three Levels of Engineering <a class="header-anchor" href="#three-levels-of-engineering" aria-label="Permalink to &quot;Three Levels of Engineering&quot;">​</a></h2><p>The field encompasses three distinct levels:</p><ol><li><strong>Prompt Engineering</strong>: Crafting specific instructions for the model</li><li><strong>Context Engineering</strong>: Managing what information the model observes and when</li><li><strong>Harness Engineering</strong>: Building complete application infrastructure controlling when context loads, which tools remain available, which actions are permitted, and how failures are handled</li></ol><p>Each level encompasses the previous one, creating a hierarchy of engineering sophistication.</p><h2 id="the-anatomy-of-a-harness" tabindex="-1">The Anatomy of a Harness <a class="header-anchor" href="#the-anatomy-of-a-harness" aria-label="Permalink to &quot;The Anatomy of a Harness&quot;">​</a></h2><p>A complete harness consists of eight interconnected components:</p><ol><li>The LLM at the core</li><li>Tools for interaction</li><li>A planning loop determining actions</li><li>Context engineering managing information flow</li><li>A sandbox for secure execution</li><li>Memory systems across multiple layers</li><li>An orchestration layer coordinating operations</li><li>A serving layer connecting to user interfaces</li></ol><h3 id="multi-surface-architecture" tabindex="-1">Multi-Surface Architecture <a class="header-anchor" href="#multi-surface-architecture" aria-label="Permalink to &quot;Multi-Surface Architecture&quot;">​</a></h3><p>Modern harnesses employ multi-surface architecture, serving the same agent across different interfaces. OpenClaw exemplifies this approach, delivering consistent agent functionality across command-line interfaces, web UIs, desktop applications, and messaging platforms through a centralized Gateway using typed WebSocket protocols.</p><p>Codex evolved from a simple terminal tool into an App Server using JSON-RPC over standard input and output. OpenCode utilizes a Bun JS HTTP server where clients connect via HTTP, with an Event Bus broadcasting results in real-time.</p><p>These architectures introduce challenges: multiple messages arrive in parallel from different clients while users submit new requests during ongoing processing. To address this, systems implement priority queues and message buses. OpenClaw uses a lane-aware FIFO queue ensuring only one active run per session while enabling parallelism across different sessions.</p><h3 id="the-filesystem-as-foundation" tabindex="-1">The Filesystem as Foundation <a class="header-anchor" href="#the-filesystem-as-foundation" aria-label="Permalink to &quot;The Filesystem as Foundation&quot;">​</a></h3><p>The filesystem emerges as the most foundational harness primitive, enabling durable storage, workspace management, multi-agent collaboration, and versioning. Remarkably, production harnesses typically use the filesystem as their primary state mechanism rather than implementing fancy vector databases.</p><p>This approach differs from traditional orchestration tools like Airflow in three critical ways:</p><ul><li>The agent loop operates non-deterministically</li><li>Context management becomes a first-class concern</li><li>The programmer inside the loop is the LLM itself</li></ul><p>Systems like Prefect, Temporal, and DBOS provide durability while supporting dynamic pipelines rather than rigid, predefined DAGs.</p><h2 id="how-agents-decide-what-to-do-next" tabindex="-1">How Agents Decide What to Do Next <a class="header-anchor" href="#how-agents-decide-what-to-do-next" aria-label="Permalink to &quot;How Agents Decide What to Do Next&quot;">​</a></h2><p>The ReAct (Reasoning and Acting) pattern represents the most common planning loop architecture. The model receives current state, reasons about the next action, executes that action through a tool call, and observes the result. This cycle repeats until a strict stopping condition triggers.</p><p>Consider a concrete example: fixing a failing test. First, the model reads test output, reasons that the import path is incorrect, and edits the file through a tool. Second, it reruns tests, identifies a new type mismatch error, and fixes it. Third, it runs tests again, they pass, and the model reasons the task is complete.</p><p>The harness orchestrates this loop while the model reasons and selects actions.</p><h3 id="orchestrator-worker-patterns" tabindex="-1">Orchestrator-Worker Patterns <a class="header-anchor" href="#orchestrator-worker-patterns" aria-label="Permalink to &quot;Orchestrator-Worker Patterns&quot;">​</a></h3><p>For complex tasks exceeding a single agent&#39;s capacity, harnesses implement orchestrator-worker patterns where the orchestrator decomposes tasks, delegates subtasks to specialized workers, and aggregates results. In OpenCode, a dedicated task tool spawns subagents, each receiving its own session, context window, and restricted tool set.</p><p>For tasks spanning multiple context windows, Claude Code implements Ralph Loops—a harness mechanism that intercepts the model&#39;s exit attempt, reinjects the original prompt in a clean context window, and forces continuation toward a completion goal using filesystem-persisted state.</p><h3 id="single-vs-multiple-agents" tabindex="-1">Single vs. Multiple Agents <a class="header-anchor" href="#single-vs-multiple-agents" aria-label="Permalink to &quot;Single vs. Multiple Agents&quot;">​</a></h3><p>The author&#39;s experience automating business operations revealed an important lesson: a single well-harnessed agent with memory and smart context engineering often outperforms multiple specialized agents. The recommendation: always start with one well-harnessed agent before pursuing multi-agent complexity.</p><h2 id="tools-that-enable-agent-action" tabindex="-1">Tools That Enable Agent Action <a class="header-anchor" href="#tools-that-enable-agent-action" aria-label="Permalink to &quot;Tools That Enable Agent Action&quot;">​</a></h2><p>Agent interaction with the environment occurs through specifically-designed toolkits for autonomous execution:</p><h3 id="general-purpose-tools" tabindex="-1">General-Purpose Tools <a class="header-anchor" href="#general-purpose-tools" aria-label="Permalink to &quot;General-Purpose Tools&quot;">​</a></h3><p><strong>Bash</strong> provides general-purpose capabilities, allowing agents to execute any shell command for tests, linters, or builds. This grants code execution capabilities, enabling models to design their own tools rather than remaining constrained by fixed options.</p><h3 id="specialized-tools" tabindex="-1">Specialized Tools <a class="header-anchor" href="#specialized-tools" aria-label="Permalink to &quot;Specialized Tools&quot;">​</a></h3><p><strong>Filesystem tools</strong> handle common operations—reading, writing, editing, and searching—more safely and efficiently than bash. A read tool might enforce absolute paths and line limits, while an edit tool validates replacement string uniqueness.</p><h3 id="state-management-tools" tabindex="-1">State Management Tools <a class="header-anchor" href="#state-management-tools" aria-label="Permalink to &quot;State Management Tools&quot;">​</a></h3><p>These track session-scoped tasks, providing working memory within a single session. OpenCode includes <code>ToDoAdd</code> and <code>ToDoRead</code> tools that manage task queues, helping agents track their execution plans.</p><h3 id="orchestration-tools" tabindex="-1">Orchestration Tools <a class="header-anchor" href="#orchestration-tools" aria-label="Permalink to &quot;Orchestration Tools&quot;">​</a></h3><p>These launch subagents with isolated prompts and context windows, such as OpenCode&#39;s task tool or Claude Code&#39;s agent tool.</p><h3 id="feedback-loop-principle" tabindex="-1">Feedback Loop Principle <a class="header-anchor" href="#feedback-loop-principle" aria-label="Permalink to &quot;Feedback Loop Principle&quot;">​</a></h3><p>The most important principle involves feedback loops. Boris Cherny, Claude Code&#39;s creator, noted that providing the model with verification capabilities improves quality by two to three times. OpenCode integrates the Language Server Protocol (LSP) to supply real-time code definitions and diagnostics, feeding undefined variables and type errors back to the LLM for immediate correction.</p><h3 id="access-control" tabindex="-1">Access Control <a class="header-anchor" href="#access-control" aria-label="Permalink to &quot;Access Control&quot;">​</a></h3><p>Harnesses enforce tool access control. In OpenCode, the planning agent cannot call edit tools, preventing exploratory agents from accidentally modifying code.</p><h2 id="where-agents-run-sandboxes" tabindex="-1">Where Agents Run: Sandboxes <a class="header-anchor" href="#where-agents-run-sandboxes" aria-label="Permalink to &quot;Where Agents Run: Sandboxes&quot;">​</a></h2><p>Agents execute code that can fail, crash, or cause system damage. Sandboxes isolate agent execution, preventing failures from affecting the host system or other agents while enabling horizontal scaling across parallel environments.</p><h3 id="security-vs-capability-tradeoff" tabindex="-1">Security vs. Capability Tradeoff <a class="header-anchor" href="#security-vs-capability-tradeoff" aria-label="Permalink to &quot;Security vs. Capability Tradeoff&quot;">​</a></h3><p>Different harnesses balance this tradeoff differently:</p><p><strong>Hard Sandbox Approach (Codex)</strong>: Each task runs in an isolated cloud container with the repository preloaded. This provides maximum safety but prevents filesystem access beyond the container.</p><p><strong>Soft Sandbox Approach (OpenClaw)</strong>: The workspace is the default working directory, granting maximum capability but introducing greater risk.</p><p>Most production harnesses occupy the middle ground, depending on the trust model.</p><h3 id="cloud-sandboxes" tabindex="-1">Cloud Sandboxes <a class="header-anchor" href="#cloud-sandboxes" aria-label="Permalink to &quot;Cloud Sandboxes&quot;">​</a></h3><p>When submitting a task to Codex, the harness spins up a fresh cloud container. The agent works inside, reading files, running tests, and installing packages, unable to touch the local machine. Upon completion, results are extracted and the container is destroyed.</p><p>Cloud sandboxes provide powerful computing resources—agents can train models using GPUs in sandbox environments powered by accelerators, similar to manually SSHing to different VMs. Multiple cloud sandboxes can be spun up for parallel agent execution.</p><h3 id="local-sandboxes" tabindex="-1">Local Sandboxes <a class="header-anchor" href="#local-sandboxes" aria-label="Permalink to &quot;Local Sandboxes&quot;">​</a></h3><p>Docker containers or isolated processes provide local alternatives, similar to Cursor&#39;s approach—useful for testing while granting agents full permissions to avoid requiring supervision.</p><h2 id="memory-across-three-layers" tabindex="-1">Memory Across Three Layers <a class="header-anchor" href="#memory-across-three-layers" aria-label="Permalink to &quot;Memory Across Three Layers&quot;">​</a></h2><p>To survive across sessions and context windows, every harness manages state across three distinct memory layers:</p><h3 id="layer-1-filesystem-long-term-memory" tabindex="-1">Layer 1: Filesystem (Long-Term Memory) <a class="header-anchor" href="#layer-1-filesystem-long-term-memory" aria-label="Permalink to &quot;Layer 1: Filesystem (Long-Term Memory)&quot;">​</a></h3><p>This durable, persistent layer survives across sessions, storing progress files, git history, and session transcripts.</p><h3 id="layer-2-ram-short-term-working-memory" tabindex="-1">Layer 2: RAM (Short-Term/Working Memory) <a class="header-anchor" href="#layer-2-ram-short-term-working-memory" aria-label="Permalink to &quot;Layer 2: RAM (Short-Term/Working Memory)&quot;">​</a></h3><p>This fast but volatile layer holds conversation history and tool results during active sessions.</p><h3 id="layer-3-context-window-what-the-model-sees" tabindex="-1">Layer 3: Context Window (What the Model Sees) <a class="header-anchor" href="#layer-3-context-window-what-the-model-sees" aria-label="Permalink to &quot;Layer 3: Context Window (What the Model Sees)&quot;">​</a></h3><p>This strictest constraint contains everything the model knows about the current task, with size limitations determining what&#39;s visible.</p><p>The harness orchestrates dynamics between these layers. On the read path, it selectively loads relevant state from disk into RAM, then assembles the context window using techniques like compaction, progressive disclosure, and just-in-time retrieval. On the write path, it persists important state back to disk after processing.</p><p>OpenClaw enforces a strict invariant: memory is always flushed to disk before being discarded from context. Rehydration is treated as a tool-shaped action where agents search and retrieve specific data rather than dumping everything into the context window.</p><h3 id="context-engineering-techniques" tabindex="-1">Context Engineering Techniques <a class="header-anchor" href="#context-engineering-techniques" aria-label="Permalink to &quot;Context Engineering Techniques&quot;">​</a></h3><p>Context engineering enables this management. When token counts exceed ninety percent of capacity, OpenCode automatically summarizes conversations. Codex assembles prompts from multiple sources and exploits prompt caching. Anthropic recommends structured note-taking files and sub-agent architectures to isolate context.</p><p>In Anthropic&#39;s long-running agent pattern, an initializer agent creates a script, progress file, and feature list. The coding agent reads git logs and progress files at each session start, updating progress as it advances. Notably, this requires no database or vector store—just the filesystem.</p><h2 id="what-s-next" tabindex="-1">What&#39;s Next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s Next&quot;">​</a></h2><p>The field is witnessing a new software development paradigm. Rather than software engineers building traditional frontend and backend applications, the next generation will construct harnesses. Harness engineering merges software engineering with AI, operating at a higher level of abstraction.</p><p>Popular tools like Claude Code represent only the beginning. No company will indefinitely depend on proprietary harnesses. Even open-source solutions like OpenCode cannot address every specific use case. Companies will inevitably build their own custom systems.</p><p>At ZTRON, the author experienced firsthand that custom systems and infrastructure finally enable agents to function reliably in production.</p><h3 id="current-limitations" tabindex="-1">Current Limitations <a class="header-anchor" href="#current-limitations" aria-label="Permalink to &quot;Current Limitations&quot;">​</a></h3><p>However, current approaches have honest limitations:</p><ul><li>Memory still breaks across long sessions</li><li>Validation loops still miss edge cases</li><li>Orchestrating hundreds of parallel agents on shared codebases remains an open research problem</li></ul><p>Harness engineering represents genuine engineering. The harness becomes its own product with its own bugs, drift, and maintenance burden.</p><hr><p><strong>Key Takeaway</strong>: The model alone doesn&#39;t determine production success. The harness—the infrastructure surrounding it—is what truly matters for reliable agent deployment.</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><h3 id="核心命題-llm-是新的作業系統" tabindex="-1">核心命題：LLM 是新的作業系統 <a class="header-anchor" href="#核心命題-llm-是新的作業系統" aria-label="Permalink to &quot;核心命題：LLM 是新的作業系統&quot;">​</a></h3><p>去除 LlamaIndex、MCP 等複雜框架，改用純 Python、簡單 API 呼叫和自製 ReAct 引擎——結果反而更好。這個親身經歷揭示：<strong>模型本身不是瓶頸，圍繞它的基礎設施才決定 Agent 是否能在生產中可靠運作</strong>。</p><p>TerminalBench 2.0 驗證了這個原則：僅改變 harness 架構，就把 DeepAgent 從 LangChain 的前 30 名外提升到前 5 名。</p><h3 id="三層工程階梯" tabindex="-1">三層工程階梯 <a class="header-anchor" href="#三層工程階梯" aria-label="Permalink to &quot;三層工程階梯&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Harness Engineering ⊇ Context Engineering ⊇ Prompt Engineering</span></span></code></pre></div><table tabindex="0"><thead><tr><th>層次</th><th>職責</th></tr></thead><tbody><tr><td><strong>Prompt Engineering</strong></td><td>為模型撰寫特定指令</td></tr><tr><td><strong>Context Engineering</strong></td><td>管理模型觀察到什麼資訊及時機</td></tr><tr><td><strong>Harness Engineering</strong></td><td>建立完整應用基礎設施（何時載入 context、哪些工具可用、哪些操作被允許、如何處理失敗）</td></tr></tbody></table><h3 id="完整-harness-的八大組件" tabindex="-1">完整 Harness 的八大組件 <a class="header-anchor" href="#完整-harness-的八大組件" aria-label="Permalink to &quot;完整 Harness 的八大組件&quot;">​</a></h3><ol><li>核心 LLM</li><li>工具（互動介面）</li><li>規劃循環（決定下一步行動）</li><li>Context engineering（管理資訊流）</li><li>沙箱（安全執行環境）</li><li>記憶系統（多層記憶）</li><li>Orchestration 層（協調操作）</li><li>Serving 層（連接用戶介面）</li></ol><h3 id="multi-surface-架構" tabindex="-1">Multi-Surface 架構 <a class="header-anchor" href="#multi-surface-架構" aria-label="Permalink to &quot;Multi-Surface 架構&quot;">​</a></h3><p>現代 harness 採用多介面架構，跨不同平台提供相同 Agent 功能：</p><ul><li><strong>OpenClaw</strong>：透過中央化 Gateway 使用型別化 WebSocket 協定，同時服務 CLI、Web UI、桌面應用、訊息平台</li><li><strong>Codex</strong>：從終端工具演化為使用 JSON-RPC over stdin/stdout 的 App Server</li><li><strong>OpenCode</strong>：Bun JS HTTP server + Event Bus 即時廣播結果</li></ul><p>多客戶端並行訊息挑戰：用 lane-aware FIFO queue 確保每個 session 只有一個活躍執行，同時允許不同 session 並行。</p><h3 id="檔案系統是最基礎的-harness-primitive" tabindex="-1">檔案系統是最基礎的 Harness Primitive <a class="header-anchor" href="#檔案系統是最基礎的-harness-primitive" aria-label="Permalink to &quot;檔案系統是最基礎的 Harness Primitive&quot;">​</a></h3><p>生產 harness 通常使用<strong>檔案系統</strong>作為主要狀態機制，而非花俏的向量資料庫。不同之處：</p><ul><li>Agent 循環非確定性執行</li><li>Context 管理是一等關注點</li><li>循環中的「程式設計師」是 LLM 本身</li></ul><p>Anthropic 長期執行 Agent 模式：初始化代理建立 script、進度檔、功能清單 → 每次 coding agent session 讀取 git log + 進度檔 → 無需資料庫或向量儲存，僅用檔案系統。</p><h3 id="ralph-loops-機制" tabindex="-1">Ralph Loops 機制 <a class="header-anchor" href="#ralph-loops-機制" aria-label="Permalink to &quot;Ralph Loops 機制&quot;">​</a></h3><p>針對跨多個 context window 的任務，Claude Code 實作 <strong>Ralph Loops</strong>：攔截模型的退出嘗試 → 在乾淨 context window 重新注入原始 prompt → 使用檔案系統持久化狀態強制繼續向完成目標推進。</p><h3 id="三層記憶架構" tabindex="-1">三層記憶架構 <a class="header-anchor" href="#三層記憶架構" aria-label="Permalink to &quot;三層記憶架構&quot;">​</a></h3><table tabindex="0"><thead><tr><th>層次</th><th>類型</th><th>特性</th></tr></thead><tbody><tr><td><strong>檔案系統</strong></td><td>長期記憶</td><td>跨 session 持久，儲存進度檔、git 歷史、session transcript</td></tr><tr><td><strong>RAM</strong></td><td>短期/工作記憶</td><td>快速但揮發，持有對話歷史和工具結果</td></tr><tr><td><strong>Context Window</strong></td><td>模型所見</td><td>最嚴格的限制，決定模型對當前任務的了解</td></tr></tbody></table><p>OpenClaw 強制不變量：記憶在從 context 丟棄前必定刷新到磁碟。Rehydration 是工具形狀的操作——agent 搜尋並檢索特定資料，而非把一切倒入 context window。</p><h3 id="單代理-vs-多代理" tabindex="-1">單代理 vs. 多代理 <a class="header-anchor" href="#單代理-vs-多代理" aria-label="Permalink to &quot;單代理 vs. 多代理&quot;">​</a></h3><p>親身經驗教訓：<strong>有記憶和智慧 context engineering 的單一優良 harness agent，往往優於多個專業化 agent</strong>。建議永遠先以一個良好 harness 的 agent 開始，然後才考慮多代理複雜性。</p><h3 id="誠實的局限性" tabindex="-1">誠實的局限性 <a class="header-anchor" href="#誠實的局限性" aria-label="Permalink to &quot;誠實的局限性&quot;">​</a></h3><ul><li>記憶在長 session 中仍會中斷</li><li>驗證循環仍會遺漏邊緣情況</li><li>在共享代碼庫上協調數百個並行 Agent 仍是開放研究問題</li></ul><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>3 層工程層級、Ralph Loops 機制、3 層記憶體架構可直接參照設計</td></tr><tr><td>B. 創新性</td><td>8/10</td><td>LLM-as-OS 比喻、Ralph Loops 命名、filesystem-as-foundation 視角原創</td></tr><tr><td>C. 證據品質</td><td>7/10</td><td>多面架構描述豐富但缺乏量化實驗數據</td></tr><tr><td>D. 技術深度</td><td>8/10</td><td>8 個組件、3 層記憶體、multi-surface 架構均有技術細節</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>LLM-as-OS 框架適用任何 agent 實作</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.8/10</strong></td><td>8×0.3+8×0.2+7×0.2+8×0.15+8×0.15 = 2.4+1.6+1.4+1.2+1.2</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/refs/harness-design.md</code><br><strong>整合狀態</strong>：待實作</p>',117)])])}const u=t(i,[["render",r]]);export{g as __pageData,u as default};
